func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		bestAssignIdx := -1
		bestCostDelta := 1e308
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		originalCosts := make([]float64, MAXASSIGNS)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}
		newAssignOriginalCost := 0.0
		if dispatch.AssignsLen < MAXASSIGNS {
			newAssignOriginalCost = dispatch.Assigns[dispatch.AssignsLen].Cost
		}

		for assignIdx := 0; assignIdx <= dispatch.AssignsLen && assignIdx < MAXASSIGNS; assignIdx++ {
			isNewAssign := false
			if assignIdx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				isNewAssign = true
			} else if assignIdx >= dispatch.AssignsLen {
				continue
			}

			savedStateExists := false
			if !isNewAssign {
				savedStateExists = true
			}

			success := dispatch.Assigns[assignIdx].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[assignIdx].GenRoute()
				if dispatch.Assigns[assignIdx].Cost >= 0 {
					costAfter := dispatch.Assigns[assignIdx].Cost
					costBefore := originalCosts[assignIdx]
					if isNewAssign {
						costBefore = newAssignOriginalCost
					}
					costDelta := costAfter - costBefore
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = assignIdx
					}
				}
				dispatch.Assigns[assignIdx].RemoveShip(shipID)
				dispatch.Assigns[assignIdx].GenRoute()
				if savedStateExists {
					dispatch.Assigns[assignIdx].Cost = originalCosts[assignIdx]
				} else {
					dispatch.Assigns[assignIdx].Cost = newAssignOriginalCost
				}
			}
		}

		if bestAssignIdx >= 0 {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
			if bestAssignIdx >= dispatch.AssignsLen && bestAssignIdx < MAXASSIGNS {
				dispatch.AssignsLen++
			}
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

