func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := 0; jj < len(oris); jj++ {
		bestAssignIdx := -1
		bestCostDelta := 1e100
		var savedState []Assign

		savedState = make([]Assign, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedState[i] = dispatch.Assigns[i]
		}

		for aa := 0; aa < dispatch.AssignsLen; aa++ {
			prevCost := dispatch.Assigns[aa].Cost
			ok := dispatch.Assigns[aa].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[aa].GenRoute()
				if dispatch.Assigns[aa].Cost >= 0 {
					costDelta := dispatch.Assigns[aa].Cost - prevCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = aa
					}
				}
			}

			dispatch.Assigns[aa] = savedState[aa]
			dispatch.Assigns[aa].GenRoute()
		}

		if bestAssignIdx == -1 {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[newIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[newIdx].GenRoute()
				}
			}
		} else {
			for i := 0; i < dispatch.AssignsLen; i++ {
				if i != bestAssignIdx {
