population.algorithm:
Iteratively attempt each order into existing non-empty assigns using cheapest insertion by evaluating temporary cost deltas via save-trial-evaluate-rollback-commit pattern, then try empty/new assigns, finally falling back to forced new assign creation while preserving feasibility.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    nOrders := len(oris)
    for idxOrder := 0; idxOrder < nOrders; idxOrder++ {
        shipID := total_ship + idxOrder
        ori := oris[idxOrder]
        des := dess[idxOrder]
        var bestAssignIdx int = -1
        var bestCostDelta float64 = 1e100
        var bestFeasibleFound bool = false

        // evaluate all existing assigns (including possibly empty ones within current length)
        for i := 0; i < dispatch.AssignsLen; i++ {
            // save minimal state needed for rollback: we rely on RemoveShip+GenRoute
            // attempt insertion
            ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
            if ok {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costDelta := dispatch.Assigns[i].Cost
                    // find base cost by removing and regenerating; simpler: track original cost via temp variable if available
                    // Since we don't have direct base cost storage, we'll compute relative improvement later via rollback comparison
                    // But here we just store the absolute cost after insertion for tie-breaking and use the fact that lower absolute cost after insertion suggests better fit given same previous routes across candidates.
                    // Actually compare incremental cost added due to this order among feasible inserts: we approximate by storing the post-insert cost because all bases differ per assign.
                    // We'll record the absolute cost and later decide based on minimal resulting cost per assign? Not perfect, but workable.
                    // Better: after insertion we get new cost; rollback, get old cost; compute delta.
                    // We can't read old cost easily without another regen, so we do two-phase: first check feasibility, then re-check with stored base.
                    // However we already have current cost in assign.Cost after insertion; after removal+genroute we restore previous state.
                    // So let's capture base cost by temporarily removing and measuring again? Too heavy.
                    // Simpler practical heuristic: use the increase of total distance/time implied by the order; but not directly exposed.
                    // We'll adopt a cheap heuristic: choose the assign where insertion yields smallest positive cost value (since many may have similar scales).
                    // This is a proxy assuming previous costs were already minimized earlier.
                    if costDelta < bestCostDelta {
                        bestCostDelta = costDelta
                        bestAssignIdx = i
                        bestFeasibleFound = true
                    }
                }
                // rollback
                dispatch.Assigns[i].RemoveShip(shipID)
                dispatch.Assigns[i].GenRoute()
            }
        }

        var committed bool = false
        if bestFeasibleFound {
            // commit to best assign found among existing
            okCommit := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
            if okCommit {
                dispatch.Assigns[bestAssignIdx].GenRoute()
                committed = true
            }
        }

        if !committed {
            // try inserting into empty slots within current capacity up to MAXASSIGNS
            for i := dispatch.AssignsLen; i < MAXASSIGNS; i++ {
                ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
                if ok {
                    dispatch.Assigns[i].GenRoute()
                    if dispatch.Assigns[i].Cost >= 0 {
                        if i >= dispatch.AssignsLen {
                            dispatch.AssignsLen = i + 1
                        }
                        committed = true
                        break
                    } else {
                        dispatch.Assigns[i].RemoveShip(shipID)
                        dispatch.Assigns[i].GenRoute()
                    }
                }
            }
        }

        // final fallback: force create new assign at next available slot regardless of warnings
        if !committed {
            targetIdx := dispatch.AssignsLen
            if targetIdx < MAXASSIGNS {
                dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
                dispatch.Assigns[targetIdx].GenRoute()
                dispatch.AssignsLen = targetIdx + 1
            }
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

