Evaluate each order's best insertion across existing and empty assign slots via incremental cost comparison, rolling back failed trials, committing minimal positive delta inserts, and ensuring every order is placed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		feasible  bool
	}
	for shipIdx := range oris {
		best := candidate{-1, 1e30, false}
		orderID := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		slotLimit := dispatch.AssignsLen
		if slotLimit == 0 {
			slotLimit = 1
		}

		for assignIdx := 0; assignIdx < MAXASSIGNS; assignIdx++ {
			isNewSlot := assignIdx >= dispatch.AssignsLen && assignIdx < MAXASSIGNS
			if isNewSlot {
				if slotLimit >= MAXASSIGNS || assignIdx != slotLimit {
