For each ship, evaluate insertion cost deltas across all existing routes via trial-and-error, pick the minimum‑cost feasible slot, otherwise create a new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	for idx := range oris {
		bestAssignIdx := -1
		bestDelta := INF_COST
		insertOk := false

		// try inserting into existing assigns
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedAssign := dispatch.Assigns[i]

			if dispatch.Assigns[i].AddShip(total_ship+idx, oris[idx], dess[idx]) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				oldCost := savedAssign.Cost
				costDelta := newCost - oldCost
				if newCost >= 0 {
					if costDelta < bestDelta {
						bestDelta = costDelta
						bestAssignIdx = i
						insertOk = true
					}
				}
				// rollback
				dispatch.Assigns[i] = savedAssign
				dispatch.Assigns[i].GenRoute()
			}
		}

		// try a brand new assign
		newIdx := dispatch.AssignsLen
		if newIdx < MAXASSIGNS {
			savedNew := dispatch.Assigns[newIdx]
			if dispatch.Assigns[newIdx].AddShip(total_ship+idx, oris[idx], dess[idx]) {
				dispatch.Assigns[newIdx].GenRoute()
				newCost := dispatch.Assigns[newIdx].Cost
				if newCost >= 0 {
					costDelta := newCost
					if costDelta < bestDelta {
						bestDelta = costDelta
						bestAssignIdx = newIdx
						insertOk = true
					}
				}
				// rollback tentative
				dispatch.Assigns[newIdx] = savedNew
				dispatch.Assigns[newIdx].GenRoute()
			}
		}

		// commit the best insertion found
		if insertOk && bestAssignIdx < dispatch.AssignsLen {
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
		} else if insertOk && bestAssignIdx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			dispatch.AssignsLen++
		} else {
			// fallback seed-style insertion into first feasible slot (new assign if needed)
			fallbackDone := false
			for i := 0; i < dispatch.AssignsLen && !fallbackDone; i++ {
				savedAssign := dispatch.Assigns[i]
				if dispatch.Assigns[i].AddShip(total_ship+idx, oris[idx], dess[idx]) {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						fallbackDone = true
						break
					}
					dispatch.Assigns[i] = savedAssign
					dispatch.Assigns[i].GenRoute()
				}
			}
			if !fallbackDone && dispatch.AssignsLen < MAXASSIGNS {
				i := dispatch.AssignsLen
				if dispatch.Assigns[i].AddShip(total_ship+idx, oris[idx], dess[idx]) {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						dispatch.AssignsLen++
						fallbackDone = true
					}
				}
			}
			// last resort: force into a fresh assign even if cost negative (should not happen under normal constraints)
			if !fallbackDone && dispatch.AssignsLen < MAXASSIGNS {
				i := dispatch.AssignsLen
				dispatch.Assigns[i] = Assign{}
				dispatch.Assigns[i].AddShip(total_ship+idx, oris[idx], dess[idx])
				dispatch.Assigns[i].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

