			savedStatCur := dispatch.Assigns[i].StationCurrent
			if dispatch.Assigns[i].AddShip(id, ori, des) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 || !found {
					delta := newCost - savedCost
					useDelta := delta
					if !found && newCost < 0 {
						useDelta = cal_dis(dispatch.Assigns[i].StationCurrent, ori)
					}
					if useDelta < bestCand.delta || (!found && newCost >= 0) {
						bestCand.idx = i
						bestCand.delta = useDelta
						bestCand.oldCost = savedCost
						bestCand.isNewSlot = false
						found = true
					}
				}
				dispatch.Assigns[i].RemoveShip(id)
				dispatch.Assigns[i].GenRoute()
				dispatch.Assigns[i].StationCurrent = savedStatCur
				dispatch.Assigns[i].Cost = savedCost
			}
		}
		if dispatch.AssignsLen < MAXASSIGNS {
			i := dispatch.AssignsLen
