func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

raw_best_population_item.algorithm:
Iteratively try each ship insertion into existing non-empty assigns sorted by increasing incremental cost, track best, rollback trials, fallback to new assign if needed, always preserve all orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	type trialResult struct {
		assignIdx int
		costDelta float64
		success   bool
	}

	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		bestTrial := trialResult{assignIdx: -1, costDelta: 0.0, success: false}

		existingNonEmptyLimit := 0
		nonEmptyIndices := make([]int, 0, MAXASSIGNS)
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen > 0 {
				nonEmptyIndices = append(nonEmptyIndices, i)
				existingNonEmptyLimit++
			}
		}
		existingNonEmptyLimit = len(nonEmptyIndices)

		candidateResults := make([]trialResult, 0, MAXASSIGNS)
		for _, idx := range nonEmptyIndices {
			assign := &dispatch.Assigns[idx]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - oldCost
				assign.RemoveShip(shipID)
				assign.GenRoute()
				if assign.Cost != oldCost {
					assign.GenRoute()
				}
				candidateResults = append(candidateResults, trialResult{assignIdx: idx, costDelta: delta, success: true})
			} else {
				assign.RemoveShip(shipID)
				if assign.StationsLen > 0 {
					assign.GenRoute()
				}
			}
		}

		if len(candidateResults) > 0 {
			minDelta := candidateResults[0].costDelta
			bestIdx := candidateResults[0].assignIdx
			for _, res := range candidateResults {
				if res.costDelta < minDelta {
					minDelta = res.costDelta
					bestIdx = res.assignIdx
				}
			}
			bestTrial = trialResult{assignIdx: bestIdx, costDelta: minDelta, success: true}
		}

		inserted := false
		if bestTrial.success {
			targetAssign := &dispatch.Assigns[bestTrial.assignIdx]
			ok := targetAssign.AddShip(shipID, ori, des)
			if ok {
				targetAssign.GenRoute()
				inserted = true
			} else {
				targetAssign.RemoveShip(shipID)
				targetAssign.GenRoute()
			}
		}

		if !inserted {
			fallbackIdx := -1
			for i := 0; i < MAXASSIGNS; i++ {
				isUsed := false
				for k := 0; k < dispatch.AssignsLen; k++ {
					if i == k {
						isUsed = true
						break
					}
				}
				if !isUsed {
					fallbackIdx = i
					break
				}
			}
			if fallbackIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
				fallbackIdx = dispatch.AssignsLen
			}
			if fallbackIdx >= 0 && fallbackIdx < MAXASSIGNS {
				assign := &dispatch.Assigns[fallbackIdx]
				if dispatch.AssignsLen <= fallbackIdx {
					dispatch.AssignsLen = fallbackIdx + 1
				}
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					inserted = true
				}
			}
		}

		if !inserted {
			emergencyIdx := dispatch.AssignsLen
			if emergencyIdx < MAXASSIGNS {
				assign := &dispatch.Assigns[emergencyIdx]
				dispatch.AssignsLen++
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					inserted = true
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

