func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || orderCount != len(dess) {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		bestAssignIdx := -1
		bestMarginalDelta := math.MaxFloat64
		originalCosts := make([]float64, MAXASSIGNS)

		// Evaluate each existing assign for insertion
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			originalCosts[i] = assign.Cost
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				if newCost >= 0 {
					marginalDelta := newCost - originalCosts[i]
					if marginalDelta < bestMarginalDelta {
						bestMarginalDelta = marginalDelta
						bestAssignIdx = i
					}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		// Fallback: try inserting into a new empty assign beyond current length
		if bestAssignIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
			candidateIdx := dispatch.AssignsLen
			assign := &dispatch.Assigns[candidateIdx]
			savedCost := assign.Cost
			savedStationCurrent := assign.StationCurrent
			savedLen := assign.StationsLen
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				if assign.Cost >= 0 {
					bestAssignIdx = candidateIdx
					bestMarginalDelta = assign.Cost
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
					assign.Cost = savedCost
					assign.StationCurrent = savedStationCurrent
					assign.StationsLen = savedLen
				}
			} else {
				assign.Cost = savedCost
				assign.StationCurrent = savedStationCurrent
				assign.StationsLen = savedLen
			}
		}

		// Commit the best insertion found
		if bestAssignIdx >= 0 {
			assign := &dispatch.Assigns[bestAssignIdx]
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestAssignIdx + 1
			}
			assign.AddShip(shipID, ori, des)
			assign.GenRoute()
		} else {
			// Emergency fallback: force create a new assign even if partially reset
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				assign := &dispatch.Assigns[idx]
				savedCost := assign.Cost
				savedStationCurrent := assign.StationCurrent
