		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			originalCosts[i] = assign.Cost
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				if newCost >= 0 {
					marginalDelta := newCost - originalCosts[i]
					if marginalDelta < bestMarginalDelta {
						bestMarginalDelta = marginalDelta
						bestAssignIdx = i
					}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		// Fallback: try inserting into a new empty assign beyond current length
		if bestAssignIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
			candidateIdx := dispatch.AssignsLen
			assign := &dispatch.Assigns[candidateIdx]
			savedCost := assign.Cost
			savedStationCurrent := assign.StationCurrent
			savedLen := assign.StationsLen
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				if assign.Cost >= 0 {
					bestAssignIdx = candidateIdx
					bestMarginalDelta = assign.Cost
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
					assign.Cost = savedCost
					assign.StationCurrent = savedStationCurrent
					assign.StationsLen = savedLen
				}
			} else {
				assign.Cost = savedCost
				assign.StationCurrent = savedStationCurrent
				assign.StationsLen = savedLen
			}
		}

		// Commit the best insertion found
		if bestAssignIdx >= 0 {
			assign := &dispatch.Assigns[bestAssignIdx]
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestAssignIdx + 1
			}
			assign.AddShip(shipID, ori, des)
			assign.GenRoute()
		} else {
			// Emergency fallback: force create a new assign even if partially reset
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				assign := &dispatch.Assigns[idx]
				savedCost := assign.Cost
				savedStationCurrent := assign.StationCurrent
				savedLen := assign.StationsLen
				if assign.AddShip(shipID, ori, des) {
					assign.GenRoute()
					if assign.Cost < 0 {
						assign.RemoveShip(shipID)
						assign.GenRoute()
						assign.Cost = savedCost
						assign.StationCurrent = savedStationCurrent
						assign.StationsLen = savedLen
					} else {
						dispatch.AssignsLen++
					}
				} else {
					assign.Cost = savedCost
					assign.StationCurrent = savedStationCurrent
					assign.StationsLen = savedLen
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
