Greedy insertion with feasibility-first ordering, scoring by normalized marginal distance plus time-window urgency, and exhaustive fallback to earliest viable empty assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 0.6
	const beta = 0.4
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	for i := 0; i < len(orderIndices)-1; i++ {
		for j := i + 1; j < len(orderIndices); j++ {
			a, b := orderIndices[i], orderIndices[j]
			wa := 0.0
			if oris[a].TimeStart > 0 && oris[a].TimeEnd > oris[a].TimeStart {
				wa = float64(oris[a].TimeEnd - oris[a].TimeStart)
			}
			wb := 0.0
			if oris[b].TimeStart > 0 && oris[b].TimeEnd > oris[b].TimeStart {
				wb = float64(oris[b].TimeEnd - oris[b].TimeStart)
			}
			if wa > wb {
				orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
			}
		}
	}
	for _, idx := range orderIndices {
		ori := oris[idx]
		des := dess[idx]
		shipID := total_ship + idx
		bestScore := math.MaxFloat64
		bestAssignIdx := -1
		baseDist := cal_dis(ori, des)
		originalCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}
		for tryAssignIdx := 0; tryAssignIdx <= dispatch.AssignsLen; tryAssignIdx++ {
			var savedCost float64
			success := false
			score := 0.0
			if tryAssignIdx < dispatch.AssignsLen {
				assignPtr := &dispatch.Assigns[tryAssignIdx]
				savedCost = assignPtr.Cost
				if assignPtr.AddShip(shipID, ori, des) {
					assignPtr.GenRoute()
					if assignPtr.Cost >= 0 {
						delta := assignPtr.Cost - savedCost
						normDelta := 0.0
						if baseDist > 0 {
							normDelta = delta / baseDist
						} else {
							normDelta = delta
						}
						urgency := 0.0
						if ori.TimeStart > 0 && ori.TimeEnd > ori.TimeStart {
							window := float64(ori.TimeEnd - ori.TimeStart)
							if window > 0 {
								midWindow := float64(ori.TimeStart) + window/2.0
								urgency = beta / (1.0 + midWindow)
							}
						}
						score = alpha*normDelta + urgency
						success = true
					}
					assignPtr.RemoveShip(shipID)
					assignPtr.GenRoute()
				}
				assignPtr.Cost = savedCost
			} else {
				if tryAssignIdx < MAXASSIGNS {
					assignPtr := &dispatch.Assigns[tryAssignIdx]
					savedCost = assignPtr.Cost
					if assignPtr.AddShip(shipID, ori, des) {
						assignPtr.GenRoute()
						if assignPtr.Cost >= 0 {
							delta := assignPtr.Cost - savedCost
							score = alpha * delta
							success = true
						}
						assignPtr.RemoveShip(shipID)
						assignPtr.GenRoute()
						assignPtr.Cost = savedCost
					}
				}
			}
			if success && score < bestScore {
				bestScore = score
				bestAssignIdx = tryAssignIdx
			}
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			dispatch.Assigns[i].Cost = originalCosts[i]
		}
		inserted := false
