					if tmp.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						tmp.RemoveShip(shipID)
						tmp.GenRoute()
					}
				}
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			fallbackIdx := dispatch.AssignsLen
			tmp := &dispatch.Assigns[fallbackIdx]
			oldSLen := tmp.StationsLen
			oldCst := tmp.Cost
			if tmp.AddShip(shipID, ori, des) {
				tmp.GenRoute()
				if tmp.Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					tmp.RemoveShip(shipID)
					tmp.StationsLen = oldSLen
					tmp.Cost = oldCst
					tmp.GenRoute()
				}
			} else {
				tmp.StationsLen = oldSLen
				tmp.Cost = oldCst
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
